import React, { useState } from 'react';
import './RolePlay.css';

export default function RolePlaySettings() {
  const [settings, setSettings] = useState({
    maxAttempts: 3,
    pronunciationThreshold: 75,
    autoAdvanceDelay: 800,
    voiceRecognition: true,
    countdownSeconds: 30,
    showRomaji: false,
    showEnglish: true,
    xpPerCorrect: 15,
    coinsPerCorrect: 5,
  });

  const [saved, setSaved] = useState(false);

  const handle = (k, v) => {
    setSaved(false);
    setSettings(prev => ({ ...prev, [k]: v }));
  };

  const handleSave = async () => {
    await new Promise(r => setTimeout(r, 600));
    setSaved(true);
  };

  const Field = ({ label, hint, children }) => (
    <div className="form-group">
      <label>{label}</label>
      {hint && <div className="rp-field-hint">{hint}</div>}
      {children}
    </div>
  );

  return (
    <div className="rp-page">
      <div className="rp-page-header">
        <div>
          <h2 className="rp-page-title">⚙️ RolePlay Settings</h2>
          <p className="rp-page-sub">Configure gameplay behaviour for all RolePlay sessions.</p>
        </div>
      </div>

      <div className="rp-settings-layout">
        {/* Speech Recognition */}
        <div className="card">
          <h3 className="rp-settings-section-title">🎤 Speech Recognition</h3>

          <Field label="Voice Recognition Enabled" hint="If disabled, all turns auto-pass after a delay.">
            <label className="toggle">
              <input type="checkbox" checked={settings.voiceRecognition} onChange={e => handle('voiceRecognition', e.target.checked)} />
              <span className="toggle-slider" />
            </label>
          </Field>

          <Field label="Pronunciation Threshold (%)" hint={`Current: ${settings.pronunciationThreshold}%. Score below this will trigger a retry.`}>
            <input
              type="range" min={50} max={100} step={5}
              value={settings.pronunciationThreshold}
              onChange={e => handle('pronunciationThreshold', Number(e.target.value))}
              disabled={!settings.voiceRecognition}
            />
            <div className="rp-range-labels">
              <span>50%</span><span style={{ fontWeight: 700, color: 'var(--primary)' }}>{settings.pronunciationThreshold}%</span><span>100%</span>
            </div>
          </Field>

          <Field label="Max Retry Attempts" hint="If exceeded, the line is marked as skipped.">
            <select value={settings.maxAttempts} onChange={e => handle('maxAttempts', Number(e.target.value))} disabled={!settings.voiceRecognition}>
              {[1,2,3,4,5].map(n => <option key={n} value={n}>{n} attempt{n !== 1 ? 's' : ''}</option>)}
            </select>
          </Field>
        </div>

        {/* Timing */}
        <div className="card">
          <h3 className="rp-settings-section-title">⏱ Timing</h3>

          <Field label="Auto-Advance Delay (ms)" hint="Time between a correct answer and the next speaker's turn.">
            <input
              type="number" min={200} max={3000} step={100}
              value={settings.autoAdvanceDelay}
              onChange={e => handle('autoAdvanceDelay', Number(e.target.value))}
            />
          </Field>

          <Field label="Character Selection Countdown (seconds)" hint="Players must select a character before this expires.">
            <input
              type="number" min={10} max={120} step={5}
              value={settings.countdownSeconds}
              onChange={e => handle('countdownSeconds', Number(e.target.value))}
            />
          </Field>
        </div>

        {/* Display */}
        <div className="card">
          <h3 className="rp-settings-section-title">🖥️ Display</h3>

          <Field label="Show Romaji" hint="Display romanized text below Japanese sentences.">
            <label className="toggle">
              <input type="checkbox" checked={settings.showRomaji} onChange={e => handle('showRomaji', e.target.checked)} />
              <span className="toggle-slider" />
            </label>
          </Field>

          <Field label="Show English Meaning" hint="Show English translation in chat bubbles.">
            <label className="toggle">
              <input type="checkbox" checked={settings.showEnglish} onChange={e => handle('showEnglish', e.target.checked)} />
              <span className="toggle-slider" />
            </label>
          </Field>
        </div>

        {/* Rewards */}
        <div className="card">
          <h3 className="rp-settings-section-title">🪙 Rewards</h3>

          <Field label="XP per Correct Line">
            <input
              type="number" min={1} max={100}
              value={settings.xpPerCorrect}
              onChange={e => handle('xpPerCorrect', Number(e.target.value))}
            />
          </Field>

          <Field label="Coins per Correct Line">
            <input
              type="number" min={1} max={50}
              value={settings.coinsPerCorrect}
              onChange={e => handle('coinsPerCorrect', Number(e.target.value))}
            />
          </Field>
        </div>
      </div>

      <div className="rp-form-actions">
        {saved && <span className="rp-saved-msg">✅ Settings saved!</span>}
        <button className="btn btn-primary" onClick={handleSave}>
          💾 Save Settings
        </button>
      </div>
    </div>
  );
}
